35	int BacktraceCommand::prepare(int argc, char* const argv[]) {
36	    if (!CoreApi::IsReady())
37	        return Command::FINISH;
38	
39	    options.dump_all = false;
40	    options.dump_detail = false;
41	    options.dump_fps.clear();
42	    options.threads.clear();
43	
44	    int opt;
45	    int option_index = 0;
46	    optind = 0; // reset
47	    static struct option long_options[] = {
48	        {"all",    no_argument,       0,  'a'},
49	        {"detail", no_argument,       0,  'd'},
50	        {"fp",     required_argument, 0,  'f'},
51	        {0,        0,                 0,   0 },
52	    };
53	
54	    while ((opt = getopt_long(argc, (char* const*)argv, "adf:",
55	                long_options, &option_index)) != -1) {
56	        switch (opt) {
57	            case 'a':
58	                options.dump_all = true;
59	                break;
60	            case 'd':
61	                options.dump_detail = true;
62	                break;
63	            case 'f': {
64	                std::unique_ptr<char[], void(*)(void*)> newpath(strdup(optarg), free);
65	                char *token = strtok(newpath.get(), ":");
66	                while (token != nullptr) {
67	                    options.dump_fps.push_back(Utils::atol(token));
68	                    token = strtok(nullptr, ":");
69	                }
70	            } break;
71	        }
72	    }
73	    options.optind = optind;
74	
75	#if defined(__AOSP_PARSER__)
76	    Android::Prepare();
77	    Android::OatPrepare();
78	#endif
79	    return Command::ONCHLD;
80	}
